script:
/* global root_element, frappe */
(() => {
	const charts = {};

	function setKpi(key, value) {
		const el = root_element.querySelector(`[data-kpi="${key}"] .qa-kpi__value`) || root_element.querySelector(`[data-kpi="${key}"]`);
		if (el) el.textContent = value == null ? "—" : String(value);
	}

	function getFilters() {
		const from = root_element.querySelector('[data-filter="from_date"]');
		const to = root_element.querySelector('[data-filter="to_date"]');
		return { from_date: from?.value, to_date: to?.value };
	}

	function renderChart(holderId, options) {
		const parent = root_element.querySelector(holderId);
		if (!parent) return;
		parent.innerHTML = "";
		if (charts[holderId]) {
			try { charts[holderId].destroy?.(); } catch (e) { /* ignore */ }
		}
		charts[holderId] = new frappe.Chart(parent, options);
	}

	function renderAll(data) {
		const k = data.kpis || {};
		setKpi("daily_checking", k.daily_checking);
		setKpi("inline_stitching", k.inline_stitching);
		setKpi("final_inspection", k.final_inspection);

		const bySource = data.by_source || [];
		renderChart("#qa-chart-source", {
			type: "pie",
			height: 260,
			data: { labels: bySource.map((d) => d.name), datasets: [{ values: bySource.map((d) => d.value) }] },
			colors: ["#5e64ff", "#ffa00a", "#28a745"],
		});

		const trend = data.daily_trend || {};
		renderChart("#qa-chart-trend", {
			type: "line",
			height: 260,
			data: {
				labels: trend.labels || [],
				datasets: (trend.datasets || []).map((ds) => ({ name: ds.name, values: ds.values })),
			},
			colors: ["#5e64ff", "#ffa00a", "#28a745"],
		});

		const os = data.order_sheet_progress || {};
		renderChart("#qa-chart-os", {
			type: "bar",
			height: 280,
			data: {
				labels: os.labels || [],
				datasets: [
					{ name: "Plan Qty", values: os.plan_qty || [] },
					{ name: "Inspected Qty", values: os.inspected_qty || [] },
				],
			},
			colors: ["#a6b1c2", "#28a745"],
		});

		const defects = data.defects_by_source || [];
		renderChart("#qa-chart-defects", {
			type: "bar",
			height: 260,
			data: { labels: defects.map((d) => d.name), datasets: [{ name: "Defect Qty", values: defects.map((d) => d.value) }] },
			colors: ["#e74c3c"],
		});

		const op = data.inline_by_operator || {};
		renderChart("#qa-chart-operator", {
			type: "bar",
			height: 260,
			data: {
				labels: op.labels || [],
				datasets: [
					{ name: "Defect Qty", values: op.defect_qty || [] },
					{ name: "Inspected Qty", values: op.inspected_qty || [] },
				],
			},
			colors: ["#e74c3c", "#5e64ff"],
		});
	}

	async function refresh() {
		root_element.classList.add("qa-home--loading");
		try {
			const filters = getFilters();
			const r = await frappe.call({
				method: "quality_addon.api.workspace_dashboard.get_workspace_charts_data",
				args: filters,
			});
			renderAll(r.message || {});
		} finally {
			root_element.classList.remove("qa-home--loading");
		}
	}

	function initDates() {
		const to = frappe.datetime.get_today();
		const from = frappe.datetime.add_days(to, -30);
		const fromEl = root_element.querySelector('[data-filter="from_date"]');
		const toEl = root_element.querySelector('[data-filter="to_date"]');
		if (fromEl && !fromEl.value) fromEl.value = from;
		if (toEl && !toEl.value) toEl.value = to;
	}

	root_element.querySelector('[data-action="refresh"]')?.addEventListener("click", refresh);
	initDates();
	refresh();
})();
